import{_ as l,o as i,c as t,ae as e}from"./chunks/framework.DhtYoOpx.js";const q=JSON.parse('{"title":"VSCode 中 Git 的 GUI 操作","description":"","frontmatter":{},"headers":[],"relativePath":"articles/utils/vscode-git.md","filePath":"articles/utils/vscode-git.md","lastUpdated":1776146674000}'),o={name:"articles/utils/vscode-git.md"};function r(u,a,d,h,s,n){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="vscode-中-git-的-gui-操作" tabindex="-1">VSCode 中 Git 的 GUI 操作 <a class="header-anchor" href="#vscode-中-git-的-gui-操作" aria-label="Permalink to &quot;VSCode 中 Git 的 GUI 操作&quot;">​</a></h1><h2 id="_1-打开-git-面板" tabindex="-1">1. 打开 Git 面板 <a class="header-anchor" href="#_1-打开-git-面板" aria-label="Permalink to &quot;1. 打开 Git 面板&quot;">​</a></h2><ul><li>快捷键：<code>Ctrl + Shift + G</code></li><li>或点击左侧源代码管理图标</li></ul><h2 id="_2-暂存更改" tabindex="-1">2. 暂存更改 <a class="header-anchor" href="#_2-暂存更改" aria-label="Permalink to &quot;2. 暂存更改&quot;">​</a></h2><ul><li>点击文件旁边的 <code>+</code> 号</li><li>或右键选择 &quot;暂存更改&quot;</li></ul><h2 id="_3-提交" tabindex="-1">3. 提交 <a class="header-anchor" href="#_3-提交" aria-label="Permalink to &quot;3. 提交&quot;">​</a></h2><ol><li>在消息框中输入提交信息</li><li>点击 <code>√</code> 或按 <code>Ctrl + Enter</code></li></ol><h2 id="_4-切换分支" tabindex="-1">4. 切换分支 <a class="header-anchor" href="#_4-切换分支" aria-label="Permalink to &quot;4. 切换分支&quot;">​</a></h2><ol><li>点击底部状态栏的分支图标</li><li>选择 &quot;创建新分支&quot; 或 &quot;切换到...&quot;</li></ol><h2 id="_5-拉取和推送" tabindex="-1">5. 拉取和推送 <a class="header-anchor" href="#_5-拉取和推送" aria-label="Permalink to &quot;5. 拉取和推送&quot;">​</a></h2><ul><li>点击 &quot;同步更改&quot; 按钮</li><li>或右键选择 &quot;拉取&quot; / &quot;推送&quot;</li></ul><h2 id="_6-查看差异" tabindex="-1">6. 查看差异 <a class="header-anchor" href="#_6-查看差异" aria-label="Permalink to &quot;6. 查看差异&quot;">​</a></h2><ul><li>点击文件查看与上一次提交的差异</li><li>修改部分用红色/绿色高亮</li></ul><h2 id="_7-解决冲突" tabindex="-1">7. 解决冲突 <a class="header-anchor" href="#_7-解决冲突" aria-label="Permalink to &quot;7. 解决冲突&quot;">​</a></h2><ol><li>打开有冲突的文件</li><li>VSCode 会用高亮显示冲突部分</li><li>选择 &quot;接受当前更改&quot;、&quot;接受传入更改&quot; 或手动编辑</li></ol><h2 id="_8-查看提交历史" tabindex="-1">8. 查看提交历史 <a class="header-anchor" href="#_8-查看提交历史" aria-label="Permalink to &quot;8. 查看提交历史&quot;">​</a></h2><ul><li>点击 &quot;提交&quot; 视图中的 &quot;更多操作&quot;</li><li>选择 &quot;查看提交历史&quot;</li></ul><h2 id="_9-隐藏更改" tabindex="-1">9. 隐藏更改 <a class="header-anchor" href="#_9-隐藏更改" aria-label="Permalink to &quot;9. 隐藏更改&quot;">​</a></h2><ul><li>右键选择 &quot;暂存&quot;</li><li>用于临时保存当前工作进度</li></ul><h2 id="_10-gitlens-扩展推荐" tabindex="-1">10. GitLens 扩展推荐 <a class="header-anchor" href="#_10-gitlens-扩展推荐" aria-label="Permalink to &quot;10. GitLens 扩展推荐&quot;">​</a></h2><p>安装 GitLens 扩展可获得更强大的功能：</p><ul><li>行级历史追溯</li><li>提交者信息显示</li><li>丰富的比较视图</li></ul>',22)])])}const _=l(o,[["render",r]]);export{q as __pageData,_ as default};
